//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include<bits/stdc++.h>using namespace std; int main(){    ios_base::sync_with_stdio(0);    cin.tie(NULL);    int test;    cin >> test;    while(test--){        int a{},b{},c{},d{};        cin >> a >> b >> c >> d;        int steps = 0;        steps+=(d-b);        if(steps<0){            cout << -1 << '\n';            continue;        }        a+=steps;        if(a<c){            cout << -1 << '\n';            continue;        }        c-a >0 ? steps+=(c-a) : steps+=( (c-a)*-1 );        if(steps<0){            cout << -1 << '\n';            continue;        }        cout << steps << '\n';    }    return 0;}